import type { CSSProperties } from "react";

export type AlignmentConfidence =
  | "asr-derived"
  | "asr-low-evidence"
  | "manual-provisional"
  // v4 cue-anchored audio: the cue's length is the TRIMMED clip's exact frame
  // count measured at generation — not inferred from ASR alignment.
  | "clip-measured";

// Silence is FIRST-CLASS and REASONED — a lesson is never silent "by accident."
// Many different needs all reduce to the same thing: the voice goes empty for a
// good reason. So the namespace is the GENERIC `gap`, never one purpose: the
// reason is metadata that lets each downstream artifact treat the kinds
// differently (a "your turn" affordance for a learner response; nothing for an
// animation hold), while the mechanism stays one. Add a new reason by extending
// this union — never by adding a purpose-named field.
export type GapReason =
  | "learner-response" // child answers a "say it with me" prompt — the wait-time; composer shows a "your turn" affordance
  | "animation-hold" // hold the picture so a visual/animation lands; voice stays empty, the picture teaches
  | "breath" // a natural inter-sentence pause (the default boundary breath)
  | "beat" // a dramatic / emphasis pause
  | (string & {}); // OPEN — future reasons extend the union; the field stays `gap`

// An intentional span of VOICE silence, declared on the cue it belongs to.
// `seconds` is the held duration; `reason` documents WHY and is carried for any
// artifact that wants to honor it (the composer shows a "your turn" affordance
// for `learner-response`, nothing for `animation-hold`).
//
// v4 (cue-anchored audio): a gap is a TIMELINE HOLD, not baked WAV silence. The
// cue's clip plays at the cue start; the reconcile then extends the cue window
// to hold the narration + this gap (`max(narration + gap, motion) + tail`), and
// nothing schedules audio across that hold — so the silence is truly free (not
// even `Buffer.alloc`). A visual-driven hold (`visualMotionSeconds` > narration)
// is the SAME philosophy via the motion budget. Both keep the one-timeline
// invariant: the silence lives in the shared cue window. (Pre-v4 baked this into
// the WAV after the clip; see docs/pipeline-architecture.md changelog.)
export type CueGap = {
  seconds: number;
  reason: GapReason;
};

export type CuePlanItem = {
  id: string;
  narration: string;
  phrase: string;
  caption?: string;
  emphasis?: boolean;
  // Optional trailing silence baked into the WAV after this cue's voice clip.
  // Omit for the default inter-cue breath (voice config `gapSeconds`).
  gap?: CueGap;
};

export type CuePlan = {
  lessonId: string;
  cues: CuePlanItem[];
};

// ── v4 cue-anchored audio ────────────────────────────────────────────────────
// THE CUE IS THE UNIT OF COORDINATION — and in v4 that is finally true for
// AUDIO too. Each spoken cue owns its own measured audio CLIP, anchored to its
// cue window the same way captions and visuals are. There is no continuous WAV
// and no silence-detection guesswork: the generator trims each clip's TTS
// padding and records its EXACT frame length, and the reconcile chains those.

// One spoken cue's measured clip + its timeline inputs, in storyboard order.
// Emitted by the voice generator (the audio truth), consumed by
// `reconcileClipTimeline`. `clipSrc` is public/-relative (Remotion serves
// static media from public/). `narrationFrames` is the trimmed clip's exact
// length — no leading/trailing TTS padding. `gap` is an optional typed silent
// HOLD after the narration that the reconcile adds to the cue window with NO
// audio scheduled across it.
export type ClipCue = {
  id: string;
  clipSrc: string;
  narrationFrames: number;
  caption: string;
  phrase?: string;
  emphasis?: boolean;
  gap?: CueGap;
  targetTokens?: string[];
};

// A placed voice clip: which file plays, at which composition frame, for how
// long. Consumed by the kit AudioLayer (one `<Sequence from={fromFrame}>` per
// clip) and to derive the bed-duck windows. Produced by `reconcileClipTimeline`.
export type VoiceClip = {
  src: string;
  fromFrame: number;
  durationInFrames: number;
};

export type AlignedLessonCue = {
  asrText?: string;
  caption: string;
  confidence: AlignmentConfidence;
  emphasis?: boolean;
  endFrame: number;
  endSeconds: number;
  id: string;
  matchScore?: number;
  matchText?: string;
  phrase: string;
  startFrame: number;
  startSeconds: number;
  targetTokens?: string[];
};

export type CaptionCue = {
  emphasis?: boolean;
  fromFrame: number;
  text: string;
  toFrame: number;
};

export type CaptionLayerTheme = {
  containerStyle?: CSSProperties;
  ribbonStyle?: CSSProperties;
  cueStyle?: CSSProperties;
  emphasisStyle?: CSSProperties;
};

// One contiguous span where the narration WAV sits below the noise floor.
// Emitted by `bin/detect-silences.mjs` for every lesson at render time.
// Consumed by the per-lesson timeline reconcile so cue boundaries snap to
// real WAV silences instead of trusting the ASR's matchText offsets.
export type SilenceInterval = {
  durationSeconds: number;
  endFrame: number;
  endSeconds: number;
  startFrame: number;
  startSeconds: number;
};

// Helper: find the WAV silence sitting at a cue boundary, keyed on its END
// frame (= the frame at which the next word starts being spoken). ASR
// endFrames typically lag the real silence onset by 100–500ms, so we look
// for any silence whose END falls within ~1s before the ASR end through
// just-past the next ASR start. Used to snap the visual cue boundary to
// the END of the real breath — so the next visual lands exactly when the
// speaker resumes, never after.
// Allow the silence's end frame to sit slightly BEFORE the ASR's reported
// narration end — ASR endFrames include ~0.12s of phonetic-tail padding
// (see `bin/asr-align.py`), so the real silence onset is often ~3–6 frames
// earlier. Anything beyond that is an intra-cue silence (mid-sentence
// breath) and must NOT be used as a cue boundary.
const BOUNDARY_LOOKBACK_FRAMES = 6;
export const findBoundarySilence = (
  silences: SilenceInterval[],
  narrationEndFrame: number,
  nextNarrationStartFrame: number,
): SilenceInterval | undefined =>
  silences.find(
    (s) =>
      s.endFrame >= narrationEndFrame - BOUNDARY_LOOKBACK_FRAMES &&
      s.endFrame <= nextNarrationStartFrame,
  );
