// reconcileCueTimeline — the kit-owned per-lesson timeline reconcile.
//
// THE CUE IS THE UNIT OF COORDINATION. Each cue gets exactly ONE timeline
// window shared by audio, visuals, and captions. AUDIO IS THE SKELETON: per
// cue the window = max(visual-motion-budget + tail, spoken-span-to-the-next-
// real-breath). Cues chain contiguously from frame 0; the composition duration
// is the last cue's endFrame.
//
// Reconcile math (ported VERBATIM from animation-test's
// src/lessons/fenYuHeLessonTimeline.ts — generalized over inputs, math
// unchanged):
//   motionFrames      = round(visualBudgetSeconds * fps) + tailFrames
//   audioSpanFrames   = audioBoundaryFrame - cueStartFrame
//   cueFrames         = max(motionFrames, audioSpanFrames)
//   cues chain end-to-end from frame 0.
//
// audioBoundaryFrame is the END of the real WAV silence sitting at the cue
// boundary (the genuine breath before the next sentence), found over the
// detected silences. We pick the LATEST silence that ends at/before the next
// cue's audio onset AND at/after this cue's motion minimum — this is robust to
// ASR overshoot on long cues (the ASR can run a cue's reported end PAST the
// real breath into the next sentence's first word, which makes a boundary-keyed
// lookup miss the breath). findBoundarySilence is kept as a secondary fallback,
// then the next cue's ASR start.
//
// PURE: no Date.now / Math.random / fs / network. Theme-agnostic. This function
// does NOT compute ducking spans — that stays a sound-kit concern in consumers.

import {
  findBoundarySilence,
  type AlignedLessonCue,
  type ClipCue,
  type SilenceInterval,
  type VoiceClip,
} from "./types";

// cueId -> visual-motion seconds (the MINIMUM motion time for the beat).
export type VisualBudgetMap = Record<string, number>;

export type ReconcileInput = {
  // ASR output, in storyboard order — the frozen audio is canonical.
  alignedCues: readonly AlignedLessonCue[];
  // detect-silences output (WAV breaths).
  silences: readonly SilenceInterval[];
  // per-cue minimum motion seconds.
  visualBudgets: VisualBudgetMap;
  // WAV-aligned total frames (the AlignedDuration constant) — used as the
  // boundary for the final cue.
  alignedDuration: number;
  fps: number;
  // breathing room so a cue never slams into the next. Default 9 (0.3s @30).
  tailFrames?: number;
  // if set, a cue missing from visualBudgets uses this; else THROW (matches
  // animation-test, which throws on a missing budget).
  defaultBudgetSeconds?: number;
};

export type ReconciledTimeline = {
  cues: AlignedLessonCue[];
  durationFrames: number;
};

// Pick the genuine breath before the next sentence: the LATEST detected silence
// whose END sits at/before the next cue's audio onset AND at/after this cue's
// motion minimum (so the cut never undercuts the motion budget). Walking the
// candidates and keeping the latest qualifying end makes this robust to ASR
// overshoot — the real breath can end BEFORE the ASR's reported cue end, so a
// lookup keyed on that end misses it. Returns undefined when none qualifies.
const findBreathBeforeNext = (
  silences: readonly SilenceInterval[],
  motionMinFrame: number,
  nextNarrationStart: number,
): SilenceInterval | undefined => {
  let best: SilenceInterval | undefined;
  for (const silence of silences) {
    if (
      silence.endFrame <= nextNarrationStart &&
      silence.endFrame >= motionMinFrame &&
      (!best || silence.endFrame > best.endFrame)
    ) {
      best = silence;
    }
  }
  return best;
};

export const reconcileCueTimeline = (
  input: ReconcileInput,
): ReconciledTimeline => {
  const {
    alignedCues,
    silences,
    visualBudgets,
    alignedDuration,
    fps,
    tailFrames = 9,
    defaultBudgetSeconds,
  } = input;

  // findBoundarySilence takes a mutable SilenceInterval[]; the inputs are
  // readonly, so pass a shallow copy. (Pure — does not mutate the source.)
  const silenceList = silences.slice();

  const cues: AlignedLessonCue[] = [];
  // Chain from frame 0: the WAV opens with lead silence before the first word,
  // so the shared timeline starts at frame 0.
  let cursor = 0;

  for (let index = 0; index < alignedCues.length; index += 1) {
    const cue = alignedCues[index];

    let budgetSeconds = visualBudgets[cue.id];
    if (budgetSeconds === undefined) {
      if (defaultBudgetSeconds === undefined) {
        throw new Error(
          `reconcileCueTimeline: no visualBudget for cue "${cue.id}"`,
        );
      }
      budgetSeconds = defaultBudgetSeconds;
    }

    const motionFrames = Math.round(budgetSeconds * fps) + tailFrames;

    // Where the next word starts (next cue's ASR start), or the WAV-aligned
    // total for the final cue. This bounds the silence search and is the
    // fallback. NOTE: the final cue uses the imported aligned DURATION constant,
    // not the last cue's endFrame.
    const nextNarrationStart =
      index + 1 < alignedCues.length
        ? alignedCues[index + 1].startFrame
        : alignedDuration;

    // Primary: the latest real breath before the next sentence, at/after the
    // motion minimum (robust to ASR overshoot). Secondary: a silence keyed on
    // the ASR end (back-compat for cues where ASR aligns cleanly). Final
    // fallback: the next cue's ASR start.
    const motionMinFrame = cursor + motionFrames;
    const breath =
      findBreathBeforeNext(silenceList, motionMinFrame, nextNarrationStart) ??
      findBoundarySilence(silenceList, cue.endFrame, nextNarrationStart);
    const audioBoundaryFrame = breath ? breath.endFrame : nextNarrationStart;

    // The cue window must hold the audio through the boundary AND give the
    // motion its full budget — whichever is longer wins.
    const audioSpanFrames = audioBoundaryFrame - cursor;
    const cueFrames = Math.max(motionFrames, audioSpanFrames);

    const startFrame = cursor;
    const endFrame = cursor + cueFrames;

    cues.push({
      ...cue,
      startFrame,
      endFrame,
      startSeconds: Number((startFrame / fps).toFixed(3)),
      endSeconds: Number((endFrame / fps).toFixed(3)),
    });

    cursor = endFrame;
  }

  // Total composition length = last reconciled cue's endFrame.
  const durationFrames = cues.length > 0 ? cues[cues.length - 1].endFrame : 0;

  return { cues, durationFrames };
};

// ─── v4: cue-anchored audio reconcile ─────────────────────────────────────────
//
// THE CUE IS THE UNIT OF COORDINATION — true for AUDIO too. Each cue owns a
// measured audio CLIP anchored to its window; there is no continuous WAV and no
// silence-detection. The generator trims each clip's TTS padding and records its
// EXACT frame length (`ClipCue.narrationFrames`); this function just chains:
//
//   motionFrames  = round(visualBudgetSeconds * fps)        // the picture's floor
//   narration     = clip.narrationFrames                    // measured, exact
//   gap           = round(clip.gap.seconds * fps) | 0       // typed silent hold
//   cueFrames     = max(narration + gap, motionFrames) + tail
//   cues chain end-to-end from frame 0.
//
// The cue's clip plays at the cue START for `narration` frames; whatever the cue
// window holds beyond that is genuine, FREE silence (no audio is scheduled across
// it) — a motion hold and/or a typed gap. Because audio is mounted per cue
// (`voiceClips`, one `<Sequence from={fromFrame}>` each), it can NEVER cross a
// cue boundary, so the continuous-WAV drift class (docs/pipeline-architecture.md
// §6) is structurally impossible. PURE: no Date.now / Math.random / fs / network.

// A reconciled cue with explicit narration/hold sub-windows. Extends
// AlignedLessonCue so `cueMap` / `cueToCaption` / scene code consume it unchanged.
export type PlacedCue = AlignedLessonCue & {
  clipSrc: string;
  narrationStartFrame: number;
  narrationEndFrame: number;
  narrationFrames: number;
  gapFrames: number;
  holdFrames: number;
};

export type ClipReconcileInput = {
  // measured clips in storyboard order (the audio truth).
  clips: readonly ClipCue[];
  // per-cue minimum motion seconds.
  visualBudgets: VisualBudgetMap;
  fps: number;
  // breathing room so a cue never slams into the next. Default 9 (0.3s @30).
  tailFrames?: number;
  // if set, a cue missing from visualBudgets uses this; else THROW.
  defaultBudgetSeconds?: number;
};

export type ReconciledClipTimeline = {
  cues: PlacedCue[];
  // per-cue voice placements for the AudioLayer (and bed-duck derivation).
  voiceClips: VoiceClip[];
  durationFrames: number;
};

export const reconcileClipTimeline = (
  input: ClipReconcileInput,
): ReconciledClipTimeline => {
  const {
    clips,
    visualBudgets,
    fps,
    tailFrames = 9,
    defaultBudgetSeconds,
  } = input;

  const cues: PlacedCue[] = [];
  const voiceClips: VoiceClip[] = [];
  let cursor = 0;

  for (const clip of clips) {
    let budgetSeconds = visualBudgets[clip.id];
    if (budgetSeconds === undefined) {
      if (defaultBudgetSeconds === undefined) {
        throw new Error(
          `reconcileClipTimeline: no visualBudget for cue "${clip.id}"`,
        );
      }
      budgetSeconds = defaultBudgetSeconds;
    }

    const motionFrames = Math.round(budgetSeconds * fps);
    const narrationFrames = Math.max(0, Math.round(clip.narrationFrames));
    const gapFrames = clip.gap
      ? Math.max(0, Math.round(clip.gap.seconds * fps))
      : 0;

    // The cue window must hold BOTH the narration + its typed silent gap AND the
    // visual motion budget — whichever is longer — plus a small tail.
    const contentFrames = Math.max(narrationFrames + gapFrames, motionFrames);
    const cueFrames = contentFrames + tailFrames;

    const startFrame = cursor;
    const endFrame = cursor + cueFrames;
    const narrationEndFrame = startFrame + narrationFrames;

    cues.push({
      id: clip.id,
      caption: clip.caption,
      phrase: clip.phrase ?? "",
      confidence: "clip-measured",
      emphasis: clip.emphasis,
      targetTokens: clip.targetTokens,
      clipSrc: clip.clipSrc,
      startFrame,
      endFrame,
      startSeconds: Number((startFrame / fps).toFixed(3)),
      endSeconds: Number((endFrame / fps).toFixed(3)),
      narrationStartFrame: startFrame,
      narrationEndFrame,
      narrationFrames,
      gapFrames,
      holdFrames: endFrame - narrationEndFrame,
    });

    if (narrationFrames > 0) {
      voiceClips.push({
        src: clip.clipSrc,
        fromFrame: startFrame,
        durationInFrames: narrationFrames,
      });
    }

    cursor = endFrame;
  }

  const durationFrames =
    cues.length > 0 ? cues[cues.length - 1].endFrame : 0;

  return { cues, voiceClips, durationFrames };
};
