import type { CSSProperties } from "react";
import { AbsoluteFill, useCurrentFrame } from "remotion";
import type { CaptionCue, CaptionLayerTheme } from "./types";

const DEFAULT_CONTAINER: CSSProperties = {
  alignItems: "center",
  justifyContent: "flex-end",
  padding: "0 112px 46px",
  pointerEvents: "none",
};

const DEFAULT_RIBBON: CSSProperties = {
  background: "rgba(20, 20, 20, 0.78)",
  borderRadius: 16,
  color: "#ffffff",
  fontSize: 32,
  fontWeight: 700,
  lineHeight: 1.25,
  maxWidth: 920,
  padding: "14px 24px",
  textAlign: "center",
};

const DEFAULT_CUE: CSSProperties = {
  margin: "0 0.18em",
};

const DEFAULT_EMPHASIS: CSSProperties = {
  color: "#FFB84D",
};

// Cross-fade envelope: each cue ramps in over FADE_FRAMES centered on its
// fromFrame and ramps out over FADE_FRAMES centered on its toFrame. Cues that
// butt end-to-end (cue A.toFrame == cue B.fromFrame) therefore overlap during
// a FADE_FRAMES-wide window with opposing alphas — i.e. a real crossfade
// instead of a single-frame hard cut. FADE_FRAMES=6 ≈ 200ms at 30fps.
const FADE_FRAMES = 6;

const cueAlpha = (cue: CaptionCue, frame: number): number => {
  const half = FADE_FRAMES / 2;
  const fadeIn = (frame - (cue.fromFrame - half)) / FADE_FRAMES;
  const fadeOut = (cue.toFrame + half - frame) / FADE_FRAMES;
  return Math.max(0, Math.min(1, fadeIn, fadeOut));
};

type Props = {
  cues: CaptionCue[];
  theme?: CaptionLayerTheme;
};

export const CaptionLayer = ({ cues, theme }: Props) => {
  const frame = useCurrentFrame();
  const visibleCues = cues
    .map((cue) => ({ cue, alpha: cueAlpha(cue, frame) }))
    .filter(({ alpha }) => alpha > 0);

  if (visibleCues.length === 0) {
    return null;
  }

  const containerStyle = { ...DEFAULT_CONTAINER, ...theme?.containerStyle };
  const ribbonStyle = { ...DEFAULT_RIBBON, ...theme?.ribbonStyle };
  const cueStyle = { ...DEFAULT_CUE, ...theme?.cueStyle };
  const emphasisStyle = { ...DEFAULT_EMPHASIS, ...theme?.emphasisStyle };

  return (
    <>
      {visibleCues.map(({ cue, alpha }) => (
        <AbsoluteFill
          key={`${cue.fromFrame}-${cue.toFrame}-${cue.text}`}
          style={{ ...containerStyle, opacity: alpha }}
        >
          <div style={ribbonStyle}>
            <span
              style={cue.emphasis ? { ...cueStyle, ...emphasisStyle } : cueStyle}
            >
              {cue.text}
            </span>
          </div>
        </AbsoluteFill>
      ))}
    </>
  );
};
