import { Html5Audio } from "remotion";
import { mediaSrc } from "../mediaSrc";
import {
  bedVolume,
  DEFAULT_MIX_CONFIG,
  type MixConfig,
  type NarrationWindow,
} from "../audioMix";

type Props = {
  /** bed key/name under `public/audio/_beds/`, e.g. "math-calm-68-cmaj". */
  bed: string;
  /** narration windows in composition frames (from ASR spans / cues). */
  windows: NarrationWindow[];
  /** total composition frames (from the reconciled timeline). */
  totalFrames: number;
  /** mix levels + ramp lengths (defaults to `DEFAULT_MIX_CONFIG`). */
  config?: MixConfig;
};

/**
 * The music bed. Deliberately NOT routed through the narration kit's
 * `AudioLayer` (which loops + lacks an edge fade — see
 * `docs/proposals/sound-layer-integration.md` §4): the bed asset is authored to
 * ≥ lesson length, so it never loops, and the §2.2 `bedVolume` envelope carries
 * the duck + 0.75s edge fades. The mix balance is consumer-overridable via
 * `config`.
 */
export const BgmLayer = ({
  bed,
  windows,
  totalFrames,
  config = DEFAULT_MIX_CONFIG,
}: Props) => (
  <Html5Audio
    src={mediaSrc(`audio/_beds/${bed}.wav`)}
    volume={(frame) => bedVolume(frame, windows, totalFrames, config)}
  />
);
