import { mediaSrc } from "./mediaSrc";
import { SFX_DEFAULT_LINEAR } from "./audioMix";

/**
 * Lesson-agnostic SFX vocabulary + registry. Sound keys are stable; the
 * composer references them by name from `audio-cues.json` and supplies the
 * FRAME (cue-relative) itself — never a frame literal here.
 *
 * Assets are author-time WAVs under `public/audio/_sfx/`. SFX sit below
 * narration and do NOT duck. Vocabulary + levels:
 * `research/music-sound-design.md` §2.4.
 */

/**
 * The motivated-SFX vocabulary mapped to existing motion primitives. The first
 * row is the original kids core (drop-in); the rest is the minted ElevenLabs
 * library stock (variants + new slots + kid-voice rewards) — all peak-normalized
 * to -3 dBFS, all reusable across lessons.
 */
export type SfxSound =
  // core kids vocabulary
  | "pop" | "chime" | "whoosh" | "tick" | "ta-da"
  // entrance / pop variants
  | "pop-2" | "pop-3"
  // reward-chime variant
  | "chime-2"
  // transition-whoosh variant
  | "whoosh-2"
  // count-tick variants
  | "tick-2" | "tick-3" | "woodblock-count"
  // success / reward variants
  | "ta-da-2" | "twinkle-reward"
  // magic / accent
  | "sparkle" | "sparkle-2" | "bell-ding"
  // utility
  | "page-turn" | "oops-soft" | "plop-soft"
  // vocal rewards (kid-voice one-shots; kept modest, skip under tone-safe beds)
  | "vox-yay" | "vox-cheer" | "vox-applause-soft" | "vox-wonder-ooh";

type SfxAsset = {
  /** public-relative path, resolved through `mediaSrc`. */
  file: string;
  /** default linear peak (0..1), below narration. */
  volume: number;
};

export const SFX_REGISTRY: Record<SfxSound, SfxAsset> = {
  // core kids vocabulary
  pop: { file: "audio/_sfx/pop.wav", volume: SFX_DEFAULT_LINEAR },
  chime: { file: "audio/_sfx/chime.wav", volume: SFX_DEFAULT_LINEAR * 0.85 },
  // whoosh is low-passed at author-time and sits a touch quieter (~-15 dB).
  whoosh: { file: "audio/_sfx/whoosh.wav", volume: SFX_DEFAULT_LINEAR * 0.75 },
  tick: { file: "audio/_sfx/tick.wav", volume: SFX_DEFAULT_LINEAR * 0.7 },
  "ta-da": { file: "audio/_sfx/ta-da.wav", volume: SFX_DEFAULT_LINEAR },
  // entrance / pop variants (match pop)
  "pop-2": { file: "audio/_sfx/pop-2.wav", volume: SFX_DEFAULT_LINEAR },
  "pop-3": { file: "audio/_sfx/pop-3.wav", volume: SFX_DEFAULT_LINEAR },
  // reward-chime variant (match chime)
  "chime-2": { file: "audio/_sfx/chime-2.wav", volume: SFX_DEFAULT_LINEAR * 0.85 },
  // transition-whoosh variant (match whoosh)
  "whoosh-2": { file: "audio/_sfx/whoosh-2.wav", volume: SFX_DEFAULT_LINEAR * 0.75 },
  // count-tick variants (match tick)
  "tick-2": { file: "audio/_sfx/tick-2.wav", volume: SFX_DEFAULT_LINEAR * 0.7 },
  "tick-3": { file: "audio/_sfx/tick-3.wav", volume: SFX_DEFAULT_LINEAR * 0.7 },
  "woodblock-count": { file: "audio/_sfx/woodblock-count.wav", volume: SFX_DEFAULT_LINEAR * 0.7 },
  // success / reward variants
  "ta-da-2": { file: "audio/_sfx/ta-da-2.wav", volume: SFX_DEFAULT_LINEAR },
  "twinkle-reward": { file: "audio/_sfx/twinkle-reward.wav", volume: SFX_DEFAULT_LINEAR * 0.85 },
  // magic / accent
  sparkle: { file: "audio/_sfx/sparkle.wav", volume: SFX_DEFAULT_LINEAR * 0.8 },
  "sparkle-2": { file: "audio/_sfx/sparkle-2.wav", volume: SFX_DEFAULT_LINEAR * 0.8 },
  "bell-ding": { file: "audio/_sfx/bell-ding.wav", volume: SFX_DEFAULT_LINEAR * 0.8 },
  // utility
  "page-turn": { file: "audio/_sfx/page-turn.wav", volume: SFX_DEFAULT_LINEAR * 0.6 },
  "oops-soft": { file: "audio/_sfx/oops-soft.wav", volume: SFX_DEFAULT_LINEAR * 0.7 },
  "plop-soft": { file: "audio/_sfx/plop-soft.wav", volume: SFX_DEFAULT_LINEAR * 0.8 },
  // vocal rewards — perceptually loud, so kept well under the voice
  "vox-yay": { file: "audio/_sfx/vox-yay.wav", volume: SFX_DEFAULT_LINEAR * 0.6 },
  "vox-cheer": { file: "audio/_sfx/vox-cheer.wav", volume: SFX_DEFAULT_LINEAR * 0.6 },
  "vox-applause-soft": { file: "audio/_sfx/vox-applause-soft.wav", volume: SFX_DEFAULT_LINEAR * 0.6 },
  "vox-wonder-ooh": { file: "audio/_sfx/vox-wonder-ooh.wav", volume: SFX_DEFAULT_LINEAR * 0.6 },
};

/** Resolve a sound key to its static asset URL. */
export const sfxSrc = (sound: SfxSound): string =>
  mediaSrc(SFX_REGISTRY[sound].file);

/** Default linear volume for a sound key. */
export const sfxDefaultVolume = (sound: SfxSound): number =>
  SFX_REGISTRY[sound].volume;

/**
 * Semitone offset → `playbackRate` for pitch-shifted one-shots (the
 * rising-pitch-per-count-step effect). Remotion `playbackRate` resamples, so a
 * higher rate raises pitch. +12 semitones = one octave = rate 2.
 */
export const semitonesToPlaybackRate = (semitones: number): number =>
  Math.pow(2, semitones / 12);
