import { Html5Audio, interpolate, Sequence } from "remotion";
import { mediaSrc } from "./mediaSrc";
import type { VoiceClip } from "./types";

type VoiceoverSpan = [number, number];

type Props = {
  bgmSrc?: string | null;
  bgmVolume?: number;
  duckedBgmVolume?: number;
  // v4 (preferred): per-cue voice clips, each anchored to its cue window. When
  // present, the bed-duck windows are derived from the clips and `voiceSrc` /
  // `voiceoverSpans` are ignored.
  voiceClips?: VoiceClip[];
  // legacy single-WAV path (pre-v4 lessons / other kit consumers).
  voiceSrc?: string | null;
  voiceVolume?: number;
  voiceDurationInFrames?: number;
  voiceFromFrame?: number;
  voiceoverSpans?: VoiceoverSpan[];
};

const volumeAtFrame = (
  frame: number,
  spans: VoiceoverSpan[],
  baseVolume: number,
  duckedVolume: number,
) => {
  const fadeFrames = 8;

  for (const [start, end] of spans) {
    if (frame >= start && frame <= end) {
      return duckedVolume;
    }

    if (frame >= start - fadeFrames && frame < start) {
      return interpolate(
        frame,
        [start - fadeFrames, start],
        [baseVolume, duckedVolume],
        {
          extrapolateLeft: "clamp",
          extrapolateRight: "clamp",
        },
      );
    }

    if (frame > end && frame <= end + fadeFrames) {
      return interpolate(
        frame,
        [end, end + fadeFrames],
        [duckedVolume, baseVolume],
        {
          extrapolateLeft: "clamp",
          extrapolateRight: "clamp",
        },
      );
    }
  }

  return baseVolume;
};

export const AudioLayer = ({
  bgmSrc,
  bgmVolume = 0.14,
  duckedBgmVolume = 0.04,
  voiceClips,
  voiceSrc,
  voiceVolume = 1,
  voiceDurationInFrames,
  voiceFromFrame = 0,
  voiceoverSpans = [],
}: Props) => {
  const useClips = Array.isArray(voiceClips) && voiceClips.length > 0;

  // Bed-duck windows: v4 derives them from the per-cue clips so the bed lifts in
  // every silent hold (motion holds, learner-response gaps) for free; legacy
  // callers pass explicit voiceoverSpans.
  const duckSpans: VoiceoverSpan[] = useClips
    ? voiceClips!.map((c) => [c.fromFrame, c.fromFrame + c.durationInFrames])
    : voiceoverSpans;

  return (
    <>
      {bgmSrc ? (
        <Html5Audio
          loop
          src={mediaSrc(bgmSrc)}
          volume={(frame) =>
            volumeAtFrame(frame, duckSpans, bgmVolume, duckedBgmVolume)
          }
        />
      ) : null}

      {useClips
        ? voiceClips!.map((clip, index) => (
            <Sequence
              key={`${clip.src}-${clip.fromFrame}-${index}`}
              from={clip.fromFrame}
              durationInFrames={clip.durationInFrames}
            >
              <Html5Audio src={mediaSrc(clip.src)} volume={voiceVolume} />
            </Sequence>
          ))
        : voiceSrc
          ? (
            <Sequence
              durationInFrames={voiceDurationInFrames}
              from={voiceFromFrame}
            >
              <Html5Audio src={mediaSrc(voiceSrc)} volume={voiceVolume} />
            </Sequence>
          )
          : null}
    </>
  );
};
